import classNames from 'classnames'
import { useNavigate } from 'react-router-dom'
import { FC, memo, useEffect, useMemo, useState } from 'react'
import { useSelector } from 'react-redux'
import { RouterState } from 'redux-first-history'
import { Menu } from '@arco-design/web-react'

import { RootState } from '@/store'
import routes from '@/routes/routes'
import type { RoutesType } from '@common/types/route'
import EllipsisText from '@common/components/EllipsisText'
import { UserState } from '@common/store/slices/user'
import { filterRootMenu, generateMenu, getMenuIcon } from '@common/utils/menu'

import './Slider.less'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'

interface CustomMenuProps {}

const CustomMenu: FC<CustomMenuProps> = () => {
  const [selectedKeys, setSelectedKeys] = useState<string[]>([])
  const [currentUserMenuList, setCurrentUserMenuList] = useState<RoutesType[]>(
    [],
  )

  const router = useSelector<RootState, RouterState>((state) => state.router)
  const { userRoleMenuList } = useSelector<RootState, UserState>(
    (state) => state.user,
  )

  const navigate = useNavigate()
  const isLanguageAR = getLanguage() === LanguageEnum.AR

  useEffect(() => {
    const pathname = router.location?.pathname as string

    const arr: string[] = []
    const paths = pathname.split('/').filter(Boolean)

    if (paths.length > 1) {
      paths.forEach((_, index) => {
        arr.push('/' + paths.slice(0, index + 1).join('/'))
      })
    } else {
      arr.push(pathname)
    }

    // 监听路径变化，更新选中的菜单项
    setSelectedKeys(arr)
  }, [router.location?.pathname, setSelectedKeys])

  useEffect(() => {
    const currentRoutes = filterRootMenu(routes)
    // 生成当前用户菜单列表
    const list = generateMenu(userRoleMenuList, currentRoutes)
    setCurrentUserMenuList(list)
  }, [userRoleMenuList])

  const defaultOpenKeys: string[] = useMemo(() => {
    return currentUserMenuList.map((item) => item.path)
  }, [currentUserMenuList])

  const renderMenuIcon = (route: RoutesType) => {
    return (
      <div
        className={classNames('menu-icon', {
          'is-mirrorable': route.iconMirror,
        })}
      >
        {getMenuIcon(route, selectedKeys)}
      </div>
    )
  }

  const renderMenuName = (route: RoutesType) => {
    const routerName = isLanguageAR ? route.nameAr : route.name
    return (
      <EllipsisText className='menu-name' position='right' text={routerName} />
    )
  }

  const renderMenu = (routes: RoutesType[]) => {
    return routes.map((route) => {
      if (route.hideInMenu) {
        return null
      }
      const icon = renderMenuIcon(route)
      const name = renderMenuName(route)
      if (route.children && route.children.length > 0 && !route.notSubMenu) {
        return (
          <Menu.SubMenu
            // selectable
            key={route.path}
            title={
              <div
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  width: '100%',
                }}
              >
                {icon}
                {name}
              </div>
            }
          >
            {renderMenu(route.children)}
          </Menu.SubMenu>
        )
      }
      return (
        <Menu.Item key={route.path}>
          {icon}
          {name}
        </Menu.Item>
      )
    })
  }

  const handleClickMenuItem = (
    key: string,
    // event: React.MouseEvent<HTMLDivElement>,
    // keyPath: string[],
  ) => {
    navigate(key)
  }

  return (
    <Menu
      autoOpen
      defaultOpenKeys={defaultOpenKeys}
      selectedKeys={selectedKeys}
      onClickMenuItem={handleClickMenuItem}
      className={'layout__slider__menu'}
      tooltipProps={{
        // blurToHide: false,
        // popupVisible: true,
        className: 'layout__slider__menu__tooltip',
        color: '#fff',
      }}
      triggerProps={{
        // blurToHide: false,
        // popupVisible: true,
        className: 'layout__slider__menu__trigger',
        style: { backgroundColor: '#fff' },
      }}
    >
      {renderMenu(currentUserMenuList)}
    </Menu>
  )
}

export default memo(CustomMenu)

import type { UserMenuItem } from '@common/types/roles'
import type { RoutesType } from '@common/types/route'
import { RoleMenuLevel } from '@common/constants/menu'
import { isCheckPermissionEnabled } from '@common/constants/env'

/**
 * 生成菜单
 *
 * @param roleMenuList 用户角色菜单列表
 * @param menuList 路由配置文件
 * @param menu 当前用户菜单列表
 */
export const generateMenu = (
  roleMenuList: UserMenuItem[],
  menuList: RoutesType[],
) => {
  // 通过开关配置是否对导航菜单的显示作权限控制
  if (!isCheckPermissionEnabled) {
    return menuList
  }

  const menu: RoutesType[] = []
  menuList.forEach((item) => {
    item = { ...item }
    const currentRoleMenu = roleMenuList.find(
      (role) => role.url === item.path && RoleMenuLevel.btnMenu !== role.level,
    )

    if (currentRoleMenu || item.path === '/') {
      if (item.children?.length > 0 && !item.notSubMenu) {
        item.children = generateMenu(roleMenuList, item.children)
      }
      menu.push({
        ...item,
        name: currentRoleMenu.nameEn,
        nameAr: currentRoleMenu.nameAr,
      })
    }
  })
  return menu
}

/**
 * 过滤根菜单
 * @param menuList
 * @returns
 */
export const filterRootMenu = (menuList: RoutesType[]) => {
  const arr: RoutesType[] = []
  menuList
    .filter((route) => route.authRoute)
    .forEach((route) => {
      if (route?.path === '/' && Array(route?.children)) {
        route?.children?.forEach((child) => {
          arr.push({ ...child })
        })
      } else {
        arr.push({ ...route })
      }
    })

  return arr
}

/**
 * 判断某个菜单路由是否处于选中态（自身或其任一子路由被选中）
 *
 * Slider 中的 selectedKeys 已包含当前 pathname 的所有祖先段路径，
 * 例如访问 /emergency-response/emergency-teams 时，
 * selectedKeys = ['/emergency-response', '/emergency-response/emergency-teams']，
 * 因此父路由 /emergency-response 也会命中。
 *
 * @param route 菜单路由
 * @param selectedKeys 当前选中的 key 列表
 */
export const isMenuRouteSelected = (
  route: RoutesType,
  selectedKeys: string[],
): boolean => {
  return selectedKeys.includes(route.path)
}

/**
 * 获取菜单应渲染的图标：选中态优先使用 selectedIcon，否则回退到 icon
 *
 * 选中 /emergency-response/emergency-teams 时，父菜单 /emergency-response
 * 显示 selectedIcon（emergency-response-icon-select.svg）；
 * 未选中时显示 icon（emergency-response-icon.svg）。
 * 未配置 selectedIcon 的菜单始终使用 icon。
 *
 * @param route 菜单路由
 * @param selectedKeys 当前选中的 key 列表
 */
export const getMenuIcon = (route: RoutesType, selectedKeys: string[]) => {
  return isMenuRouteSelected(route, selectedKeys) && route.selectedIcon
    ? route.selectedIcon
    : route.icon
}

export const getRoleRoutePath = (userRoleMenuList: UserMenuItem[]) => {
  if (userRoleMenuList.length === 0) return '/'
  const currentRoute = userRoleMenuList[0]

  const findChildRoute = userRoleMenuList.find(
    (route) =>
      route.url?.includes(currentRoute.url) &&
      route.level === RoleMenuLevel.twoMenu,
  )

  return findChildRoute ? findChildRoute.url : currentRoute.url
}

